// src/components/Projects.jsx
// ─────────────────────────────────────────────
// Sección de proyectos
// Para añadir un proyecto nuevo: copia uno de los objetos
// del array `projects` y rellena los campos.
// ─────────────────────────────────────────────

import { useState } from 'react';

const projects = [
  {
    id: 'portfolio',
    name: 'Portfolio personal',
    desc: 'Este mismo sitio. Diseñado y desarrollado desde cero con React — sin plantillas, sin librerías de UI. Cada sección pensada para comunicar quién soy a un reclutador en menos de 30 segundos.',
    tags: ['Proyecto real'],
    stack: ['React', 'Vite', 'Vercel'],
    url: 'https://www.unsitiogenial.es',
    github: null,
    thumb: 'portfolio',
  },
  {
    id: 'clase',
    name: 'Proyecto de clase',               // ← Cambia el nombre
    desc: 'Añade aquí la descripción de tu proyecto — qué hace, qué tecnologías usa y qué aprendiste construyéndolo.',
    tags: ['DAW', 'Formación'],
    stack: ['HTML', 'CSS', 'JavaScript'],     // ← Actualiza el stack
    url: null,                                // ← Pon la URL cuando esté desplegado
    github: null,                             // ← Pon el repo si es público
    thumb: 'wip',
  },
];

export default function Projects() {
  const [hovered, setHovered] = useState(null);

  return (
    <section id="projects" style={s.section}>
      <div style={s.inner}>

        {/* Header */}
        <div style={s.header}>
          <p style={s.label}><span style={s.labelLine} />Proyectos</p>
          <h2 style={s.title}>Lo que he <em style={s.titleEm}>construido</em></h2>
          <p style={s.sub}>Proyectos reales — no ejercicios, cosas que funcionan.</p>
        </div>

        {/* Grid */}
        <div style={s.grid}>

          {projects.map((proj, i) => (
            <div
              key={proj.id}
              style={{
                ...s.card,
                ...(hovered === i ? s.cardHover : {}),
              }}
              onMouseEnter={() => setHovered(i)}
              onMouseLeave={() => setHovered(null)}
            >
              {/* Thumbnail */}
              <div style={{
                ...s.thumb,
                background: proj.thumb === 'portfolio'
                  ? 'linear-gradient(135deg, rgba(232,58,58,0.18) 0%, rgba(10,10,12,0.9) 100%)'
                  : 'linear-gradient(135deg, rgba(255,255,255,0.04) 0%, rgba(10,10,12,0.95) 100%)',
              }}>
                {proj.thumb === 'portfolio' ? (
                  <div style={s.thumbPortfolio}>
                    <div style={s.thumbRM}>RM.</div>
                    <div style={s.thumbRMSub}>portfolio</div>
                  </div>
                ) : (
                  <div style={s.thumbWip}>
                    <span style={s.thumbWipDot} />
                    En desarrollo
                  </div>
                )}
              </div>

              {/* Body */}
              <div style={s.body}>
                <div style={s.tags}>
                  {proj.tags.map((tag, ti) => (
                    <span key={ti} style={ti === 0 ? s.tagAccent : s.tag}>{tag}</span>
                  ))}
                </div>

                <div style={s.name}>{proj.name}</div>
                <p style={s.desc}>{proj.desc}</p>

                <div style={s.footer}>
                  <div style={s.links}>
                    {proj.url ? (
                      <a
                        href={proj.url}
                        target="_blank"
                        rel="noreferrer"
                        style={s.linkPrimary}
                        onMouseEnter={e => { e.currentTarget.style.gap = '10px'; }}
                        onMouseLeave={e => { e.currentTarget.style.gap = '6px'; }}
                      >
                        Ver en vivo →
                      </a>
                    ) : (
                      <span style={s.linkWip}>
                        <span style={s.wipDot} />
                        Próximamente
                      </span>
                    )}
                    {proj.github && (
                      <a
                        href={proj.github}
                        target="_blank"
                        rel="noreferrer"
                        style={s.linkGithub}
                      >
                        GitHub
                      </a>
                    )}
                  </div>

                  <div style={s.stackRow}>
                    {proj.stack.map((tech, ti) => (
                      <span key={ti} style={s.stackItem}>
                        {ti > 0 && <span style={s.stackSep}>·</span>}
                        {tech}
                      </span>
                    ))}
                  </div>
                </div>
              </div>
            </div>
          ))}

          {/* Card placeholder — desaparece cuando añadas más proyectos */}
          <div style={s.addCard}>
            <div style={s.addIcon}>+</div>
            <div style={s.addTitle}>Próximo proyecto</div>
            <p style={s.addText}>Esta sección crece contigo.</p>
          </div>

        </div>
      </div>
    </section>
  );
}

const s = {
  section: { background: 'var(--bg)', padding: '110px 5%' },
  inner: { maxWidth: 1200, margin: '0 auto' },

  header: { marginBottom: 64 },
  label: {
    fontSize: 11, fontWeight: 600, letterSpacing: '0.2em',
    textTransform: 'uppercase', color: 'var(--accent)',
    marginBottom: 12, display: 'flex', alignItems: 'center', gap: 10,
  },
  labelLine: { display: 'inline-block', width: 28, height: 1, background: 'var(--accent)' },
  title: {
    fontFamily: 'var(--font-head)',
    fontSize: 'clamp(36px, 5vw, 54px)',
    fontWeight: 900, letterSpacing: '-3px',
    color: 'var(--text)', lineHeight: 1, marginBottom: 12,
  },
  titleEm: {
    fontFamily: 'Georgia, "Times New Roman", serif',
    fontStyle: 'italic', fontWeight: 400,
    color: 'var(--accent)', letterSpacing: '-1px',
  },
  sub: { fontSize: 15, color: 'rgba(255,255,255,0.3)', fontWeight: 300 },

  grid: {
    display: 'grid',
    gridTemplateColumns: 'repeat(auto-fit, minmax(340px, 1fr))',
    gap: 16,
  },

  card: {
    background: 'var(--card)',
    border: '1px solid rgba(255,255,255,0.07)',
    borderRadius: 16, overflow: 'hidden',
    transition: 'transform 0.3s cubic-bezier(0.34,1.56,0.64,1), box-shadow 0.3s, border-color 0.25s',
    cursor: 'default',
  },
  cardHover: {
    transform: 'translateY(-6px)',
    boxShadow: '0 20px 50px rgba(0,0,0,0.4)',
    borderColor: 'rgba(232,58,58,0.25)',
  },

  thumb: {
    height: 180, display: 'flex',
    alignItems: 'center', justifyContent: 'center',
  },
  thumbPortfolio: { textAlign: 'center' },
  thumbRM: {
    fontFamily: 'var(--font-head)',
    fontSize: 36, fontWeight: 900,
    color: 'rgba(232,58,58,0.55)',
    letterSpacing: '-2px', lineHeight: 1,
  },
  thumbRMSub: {
    fontSize: 10, color: 'rgba(255,255,255,0.18)',
    letterSpacing: '0.14em', textTransform: 'uppercase', marginTop: 4,
  },
  thumbWip: {
    display: 'flex', alignItems: 'center', gap: 8,
    fontSize: 11, color: 'rgba(255,255,255,0.2)',
